// OrderServiceServer is the server API for OrderService service.
// All implementations must embed UnimplementedOrderServiceServer
// for forward compatibility.
//
// OrderService handles plans, subscriptions, bid purchases, and marketplace orders.
// Payment initiation is delegated to PaymentService via BFF orchestration.
type OrderServiceServer interface {
	// === Plans (admin) ===
	ListPlans(context.Context, *ListPlansRequest) (*ListPlansResponse, error)
	CreatePlan(context.Context, *CreatePlanRequest) (*CreatePlanResponse, error)
	UpdatePlan(context.Context, *UpdatePlanRequest) (*UpdatePlanResponse, error)
	SetPlanPrices(context.Context, *SetPlanPricesRequest) (*SetPlanPricesResponse, error)
	// === Subscriptions ===
	CreateSubscription(context.Context, *CreateSubscriptionRequest) (*CreateSubscriptionResponse, error)
	GetSubscription(context.Context, *GetSubscriptionRequest) (*GetSubscriptionResponse, error)
	GetSubscriptionsByOrg(context.Context, *GetSubscriptionsByOrgRequest) (*GetSubscriptionsByOrgResponse, error)
	CancelSubscription(context.Context, *CancelSubscriptionRequest) (*CancelSubscriptionResponse, error)
	CheckBidAccess(context.Context, *CheckBidAccessRequest) (*CheckBidAccessResponse, error)
	CalculateSubscriptionPrice(context.Context, *CalculateSubscriptionPriceRequest) (*CalculateSubscriptionPriceResponse, error)
	GetSubscriptionStatus(context.Context, *GetSubscriptionStatusRequest) (*GetSubscriptionStatusResponse, error)
	// === Bid purchases ===
	PurchaseBid(context.Context, *PurchaseBidRequest) (*PurchaseBidResponse, error)
	GetBidPurchase(context.Context, *GetBidPurchaseRequest) (*GetBidPurchaseResponse, error)
	GetBidPurchasePrice(context.Context, *GetBidPurchasePriceRequest) (*GetBidPurchasePriceResponse, error)
	// === Bid purchase prices (admin CRUD) ===
	ListBidPurchasePrices(context.Context, *ListBidPurchasePricesRequest) (*ListBidPurchasePricesResponse, error)
	CreateBidPurchasePrice(context.Context, *CreateBidPurchasePriceRequest) (*CreateBidPurchasePriceResponse, error)
	UpdateBidPurchasePrice(context.Context, *UpdateBidPurchasePriceRequest) (*UpdateBidPurchasePriceResponse, error)
	DeleteBidPurchasePrice(context.Context, *DeleteBidPurchasePriceRequest) (*DeleteBidPurchasePriceResponse, error)
	// === Orders (parts marketplace) ===
	CreateOrder(context.Context, *CreateOrderRequest) (*CreateOrderResponse, error)
	GetOrder(context.Context, *GetOrderRequest) (*GetOrderResponse, error)
	ListOrders(context.Context, *ListOrdersRequest) (*ListOrdersResponse, error)
	ConfirmShipment(context.Context, *ConfirmShipmentRequest) (*ConfirmShipmentResponse, error)
	ConfirmReceipt(context.Context, *ConfirmReceiptRequest) (*ConfirmReceiptResponse, error)
	CancelOrder(context.Context, *CancelOrderRequest) (*CancelOrderResponse, error)
	GetOrdersByCheckoutId(context.Context, *GetOrdersByCheckoutIdRequest) (*GetOrdersByCheckoutIdResponse, error)
	// === Workshop orders (parts in repair orders) ===
	CreateWorkshopOrder(context.Context, *CreateWorkshopOrderRequest) (*CreateWorkshopOrderResponse, error)
	GetOrderByRepairOrderId(context.Context, *GetOrderByRepairOrderIdRequest) (*GetOrderByRepairOrderIdResponse, error)
	GetOrderByRepairOrderAndSeller(context.Context, *GetOrderByRepairOrderAndSellerRequest) (*GetOrderByRepairOrderAndSellerResponse, error)
	ListOrdersByRepairOrderId(context.Context, *ListOrdersByRepairOrderIdRequest) (*ListOrdersByRepairOrderIdResponse, error)
	AddOrderItem(context.Context, *AddOrderItemRequest) (*AddOrderItemResponse, error)
	UpdateOrderItem(context.Context, *UpdateOrderItemRequest) (*UpdateOrderItemResponse, error)
	DeleteOrderItem(context.Context, *DeleteOrderItemRequest) (*DeleteOrderItemResponse, error)
	UpdateDeliveryStatus(context.Context, *UpdateDeliveryStatusRequest) (*UpdateDeliveryStatusResponse, error)
	SetOrderStatus(context.Context, *SetOrderStatusRequest) (*SetOrderStatusResponse, error)
	// === Maintenance offers and payable quotes ===
	ListMaintenanceOffers(context.Context, *ListMaintenanceOffersRequest) (*ListMaintenanceOffersResponse, error)
	CreateMaintenanceQuote(context.Context, *CreateMaintenanceQuoteRequest) (*CreateMaintenanceQuoteResponse, error)
	GetMaintenanceQuote(context.Context, *GetMaintenanceQuoteRequest) (*GetMaintenanceQuoteResponse, error)
	// === Basket (parts cart) payable quote ===
	// GetBasketQuote is the authoritative pricing projection for combined-pay
	// entity_type=basket. payment_entity_id carries the cart ID. Amounts are in
	// currency minor units (tiyn for KZT).
	GetBasketQuote(context.Context, *GetBasketQuoteRequest) (*GetBasketQuoteResponse, error)
	// === Admin analytics ===
	GetSubscriptionStats(context.Context, *GetSubscriptionStatsRequest) (*GetSubscriptionStatsResponse, error)
	mustEmbedUnimplementedOrderServiceServer()
}

